# pip install hubspot-api-client
import os
import json
from hubspot import HubSpot
from hubspot.crm.contacts import SimplePublicObjectInputForCreate

hs = HubSpot(access_token=os.environ["HUBSPOT_TOKEN"])

def search_contacts(query: str, limit: int = 5) -> list[dict]:
    """Search HubSpot contacts by name or email."""
    from hubspot.crm.contacts import PublicObjectSearchRequest, Filter, FilterGroup
    search_req = PublicObjectSearchRequest(
        query=query,
        limit=limit,
        properties=["firstname", "lastname", "email", "company", "phone"],
    )
    response = hs.crm.contacts.search_api.do_search(search_req)
    results = []
    for r in response.results:
        props = r.properties
        results.append({
            "id": r.id,
            "name": f"{props.get('firstname', '')} {props.get('lastname', '')}".strip(),
            "email": props.get("email"),
            "company": props.get("company"),
            "phone": props.get("phone"),
        })
    return results

def get_contact(contact_id: str) -> dict:
    """Get a single HubSpot contact by ID."""
    contact = hs.crm.contacts.basic_api.get_by_id(
        contact_id,
        properties=["firstname", "lastname", "email", "company", "hs_lead_status"],
    )
    return {
        "id": contact.id,
        "name": f"{contact.properties.get('firstname', '')} {contact.properties.get('lastname', '')}".strip(),
        "email": contact.properties.get("email"),
        "company": contact.properties.get("company"),
        "lead_status": contact.properties.get("hs_lead_status"),
    }

def create_contact_note(contact_id: str, note: str) -> dict:
    """Add a note to a HubSpot contact."""
    from hubspot.crm.objects.notes import SimplePublicObjectInputForCreate as NoteInput
    note_obj = NoteInput(
        properties={
            "hs_note_body": note,
            "hs_timestamp": "2025-01-01T00:00:00.000Z",  # use current time in production
        }
    )
    result = hs.crm.objects.notes.basic_api.create(note_obj)
    # Associate with contact
    hs.crm.objects.notes.associations_api.create(
        result.id, "contacts", contact_id, [{"associationCategory": "HUBSPOT_DEFINED", "associationTypeId": 202}]
    )
    return {"note_id": result.id, "contact_id": contact_id}

HUBSPOT_TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "search_contacts",
            "description": (
                "Search HubSpot CRM contacts by name or email. Use when the user "
                "mentions a customer, prospect, or contact name without giving an ID. "
                "Returns basic contact info including company and email."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "query": {"type": "string", "description": "Name or email to search for."},
                    "limit": {"type": "integer", "default": 5, "minimum": 1, "maximum": 20},
                },
                "required": ["query"],
                "additionalProperties": False,
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "create_contact_note",
            "description": (
                "Add a note to a HubSpot contact record. Use after confirming "
