                "confirming the correct contact."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "contact_id": {"type": "string", "description": "HubSpot contact ID (from search results)."},
                    "note": {"type": "string", "description": "Note text to add to the contact record."},
                },
                "required": ["contact_id", "note"],
                "additionalProperties": False,
