# pip install google-api-python-client google-auth
import os
from google.oauth2 import service_account
from googleapiclient.discovery import build
from datetime import datetime, timezone, timedelta

SCOPES = ["https://www.googleapis.com/auth/calendar"]
creds = service_account.Credentials.from_service_account_file(
    os.environ["GOOGLE_SERVICE_ACCOUNT_JSON"],
    scopes=SCOPES,
).with_subject("calendar-agent@example.com")   # delegate to a user

calendar_service = build("calendar", "v3", credentials=creds)

def list_upcoming_events(calendar_id: str = "primary", max_results: int = 5) -> list[dict]:
    """List upcoming calendar events."""
    now = datetime.now(timezone.utc).isoformat()
    result = calendar_service.events().list(
        calendarId=calendar_id,
        timeMin=now,
        maxResults=max_results,
        singleEvents=True,
        orderBy="startTime",
    ).execute()
    events = []
    for e in result.get("items", []):
        start = e["start"].get("dateTime", e["start"].get("date"))
        events.append({
            "id": e["id"],
            "summary": e.get("summary", "(no title)"),
            "start": start,
            "attendees": [a["email"] for a in e.get("attendees", [])],
        })
    return events

def create_event(
    title: str,
    start_datetime: str,
    end_datetime: str,
    attendee_emails: list[str] | None = None,
    description: str = "",
) -> dict:
    """Create a Google Calendar event."""
    body = {
        "summary": title,
        "description": description,
        "start": {"dateTime": start_datetime, "timeZone": "UTC"},
        "end": {"dateTime": end_datetime, "timeZone": "UTC"},
    }
    if attendee_emails:
        body["attendees"] = [{"email": e} for e in attendee_emails]
    event = calendar_service.events().insert(
        calendarId="primary",
        body=body,
        sendUpdates="all",   # send invite emails to attendees
    ).execute()
    return {"event_id": event["id"], "html_link": event.get("htmlLink")}

CALENDAR_TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "list_upcoming_events",
            "description": "List upcoming Google Calendar events. Use to check what is scheduled before booking new meetings.",
            "parameters": {
                "type": "object",
