# pip install slack-sdk
import os
from slack_sdk import WebClient
from slack_sdk.errors import SlackApiError

slack = WebClient(token=os.environ["SLACK_BOT_TOKEN"])

def post_slack_message(channel: str, text: str, thread_ts: str | None = None) -> dict:
    """Post a message to a Slack channel or thread."""
    try:
        kwargs = {"channel": channel, "text": text}
        if thread_ts:
            kwargs["thread_ts"] = thread_ts
        response = slack.chat_postMessage(**kwargs)
        return {"ts": response["ts"], "channel": response["channel"]}
    except SlackApiError as e:
        return {"error": e.response["error"]}

def list_slack_channels(limit: int = 20) -> list[dict]:
    """List public Slack channels."""
    response = slack.conversations_list(limit=limit, types="public_channel")
    return [
        {"id": c["id"], "name": c["name"], "topic": c.get("topic", {}).get("value", "")}
        for c in response["channels"]
    ]

def search_slack_messages(query: str, count: int = 5) -> list[dict]:
    """Search Slack messages. Requires search:read scope."""
    response = slack.search_messages(query=query, count=count)
    matches = response.get("messages", {}).get("matches", [])
    return [
        {
            "text": m.get("text", ""),
            "user": m.get("username", ""),
            "channel": m.get("channel", {}).get("name", ""),
            "ts": m.get("ts"),
        }
        for m in matches
    ]

SLACK_TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "post_slack_message",
            "description": (
                "Send a message to a Slack channel. Use the channel name (e.g. '#engineering') "
                "or channel ID. Requires confirmation from the user before sending "
                "unless they explicitly asked you to send a message."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "channel": {"type": "string", "description": "Channel name (e.g. 'general') or ID."},
                    "text": {"type": "string", "description": "Message text. Supports Slack markdown."},
                    "thread_ts": {
                        "anyOf": [{"type": "string"}, {"type": "null"}],
                        "description": "Thread timestamp to reply to. Null for a new top-level message.",
                        "default": None,
                    },
                },
                "required": ["channel", "text"],
                "additionalProperties": False,
            },
        },
    },
]

# pip install sendgrid
import os
from sendgrid import SendGridAPIClient
from sendgrid.helpers.mail import Mail

sg = SendGridAPIClient(api_key=os.environ["SENDGRID_API_KEY"])
SENDER_EMAIL = "assistant@example.com"
SENDER_NAME = "AI Assistant"

# Allowlist pattern — only send to pre-approved addresses
ALLOWED_RECIPIENTS = {"alice@example.com", "bob@example.com"}

def send_email(to_email: str, subject: str, body: str) -> dict:
    """Send a plain-text email via SendGrid."""
    if to_email not in ALLOWED_RECIPIENTS:
        return {"error": f"Email address {to_email!r} is not in the allowed list."}
    message = Mail(
        from_email=(SENDER_EMAIL, SENDER_NAME),
        to_emails=to_email,
        subject=subject,
        plain_text_content=body,
    )
    try:
        response = sg.send(message)
        return {"status_code": response.status_code, "to": to_email}
    except Exception as e:
        return {"error": str(e)}

SEND_EMAIL_TOOL = {
    "type": "function",
    "function": {
