from openai import OpenAI
import json

client = OpenAI()

# Combine all tools from above
ALL_TOOLS = CALENDAR_TOOLS + SLACK_TOOLS + HUBSPOT_TOOLS + [SEND_EMAIL_TOOL]

TOOL_MAP = {
    "list_upcoming_events": list_upcoming_events,
    "create_event": create_event,
    "post_slack_message": post_slack_message,
    "list_slack_channels": list_slack_channels,
    "search_contacts": search_contacts,
    "create_contact_note": create_contact_note,
    "send_email": send_email,
}

def run_business_agent(user_message: str) -> str:
    messages = [
        {
            "role": "system",
            "content": (
                "You are a business assistant with access to calendar, Slack, CRM, and email tools. "
                "Always confirm before sending messages, creating records, or taking irreversible actions. "
                "Check existing data (search contacts, list events) before creating new records."
            ),
        },
        {"role": "user", "content": user_message},
    ]
    while True:
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            tools=ALL_TOOLS,
            tool_choice="auto",
        )
        choice = response.choices[0]
        messages.append(choice.message)
        if choice.finish_reason == "stop":
            return choice.message.content
        for tc in choice.message.tool_calls:
            args = json.loads(tc.function.arguments)
            try:
                result = TOOL_MAP[tc.function.name](**args)
            except Exception as e:
                result = {"error": str(e)}
            messages.append({
                "role": "tool",
                "tool_call_id": tc.id,
                "content": json.dumps(result, default=str),
            })

print(run_business_agent("Who do I have meetings with today and what are their HubSpot lead statuses?"))
